local GUIGoodsDetailContent = class("GUIGoodsDetailContent", IGUILayout)

function GUIGoodsDetailContent:onLoad()
    self.ivContent = self:getChildWindow("GoodsDetailContent-Content", GUIType.StaticImage)
    self.ivImage = self:getChildWindow("GoodsDetailContent-Image", GUIType.StaticImage)
    self.tvName = self:getChildWindow("GoodsDetailContent-Name", GUIType.StaticText)
    self.llPrice = self:getChildWindow("GoodsDetailContent-Price-Layout", GUIType.Layout)
    self.ivPriceIcon = self:getChildWindow("GoodsDetailContent-Price-Icon", GUIType.StaticImage)
    self.tvPriceText = self:getChildWindow("GoodsDetailContent-Price-Text", GUIType.StaticText)
end

GoodsDetailContent = buildCustomDialogContent(GUIGoodsDetailContent, "GoodsDetailContent.json")

function GoodsDetailContent:setGoodsInfo(image, name, price_icon, price)
    self.ivImage:SetImage(image)
    self.tvName:SetText(Lang:getString(name))
    self.ivPriceIcon:SetImage(price_icon)
    self.tvPriceText:SetText(tostring(price))
    self.llPrice:SetVisible(true)
    self.ivContent:SetYPosition({ 0, -18 })
end

function GoodsDetailContent:hidePriceLayout()
    SoundUtil.playSound(SoundConfig.closeRewardDetail)
    self.llPrice:SetVisible(false)
    self.ivContent:SetYPosition({ 0, 0 })
end